import { useState, useRef, useEffect } from "react";

const DOCS = [
  { name: "Account Tags and Statuses Overview", tags: ["tags","status","suspended","closed","charged-off","tier"], content: `ACCOUNT TAGS AND STATUSES - IBCC\n\nThree layers when reviewing an account:\n- Layer 1: Primary Status (Master State) - system generated, cannot be manually changed. Values: Active, Suspended, Closed, Charged-Off, Terminated\n- Layer 2: Status Tags (Drivers) - control if card is blocked or rewards redeemable. Multiple tags can exist at once.\n- Layer 3: Informative Tags - context only, do not change account behavior (e.g. Hardship Assistance)\n\nSTATUS TAG MATRIX:\nActive: Disaster Recovery - no block, rewards OK, statements OK, reversible\nSuspended tags (ALL block txns, NO rewards, statements continue, all reversible):\n- Delinquent (System) - auto reverses upon cure\n- Generic Restricted - owner: Tier-2/Fraud\n- Suspected First Party Fraud - owner: Tier-2/Fraud\n- Suspected Third Party Fraud - owner: Tier-2/Fraud\n- Open ATO - owner: Tier-2/Fraud\n- Suspected OFAC - owner: Tier-2\n- Pending Deceased - owner: Tier-2\n- Pending Bankruptcy - owner: Tier-2\n- Hardship - owner: TBD\n- Pending Settlement - owner: TBD\nClosed tags (ALL block txns, NO rewards):\n- Customer Initiated - reversible: Conditional, owner: Tier-2\n- Issuer Initiated - reversible: Conditional, owner: Tier-3/Fraud\n- Confirmed First Party Fraud - Operationally Final, owner: Fraud\n- Confirmed OFAC - Compliance Controlled, owner: Tier-3\n- Settlement >=600 / Settlement - Final Closure, owner: TBD\nCharged-Off tags (ALL block txns, NO rewards, NO statements, NON-REVERSIBLE):\n- Charge-Off (System)\n- Confirmed Bankruptcy - Auto Charge-Off, owner: Tier-3\n- Confirmed Deceased - Auto Charge-Off, owner: Tier-3\n- Confirmed Third Party Fraud - Auto Charge-Off, owner: Fraud\nTerminated: Terminated (System) - NON-REVERSIBLE\n\nTIER-1 AGENT PROCEDURE - VIEW ONLY ACCESS:\nCan: View Primary Status, View Status Tags, View Informative Tags, Escalate to Tier-2/Fraud/Tier-3\nCannot: Add or remove any Status Tags, Apply Informative Tags (unless separately approved)\n\nOperating Standard: Review Primary Status > Review full Status Tag stack > Review Informative Tags > Determine escalation need.\nIMPORTANT: If a card is blocked, always review the full tag stack - multiple conditions may coexist.` },
  { name: "Administrator and Authorized Users Overview", tags: ["admin","authorized user","AU","administrator","privileges","permissions","close account"], content: `ADMINISTRATOR AND AUTHORIZED USERS OVERVIEW - IBCC\n\nDEFINITIONS:\n- Administrator: Persons designated by account owner to perform administrative functions. CANNOT close the account.\n- Authorized User (AU): Person for whom account owner or Admin has requested a credit card. Must be at least 18 years of age.\n\nKEY RULES:\n- Only account owner can close the account\n- Removal of Administrator can ONLY be completed in writing - NOT over the phone\n- AUs can only be added or removed via mobile app or removed over the phone\n- No limit on number of authorized users\n- AUs are not financially responsible for balance\n- AUs have their own individual card and card number\n\nPRIVILEGES:\nAccount Owner can do everything.\nAdministrator can: activate cards for team members, add authorized users, make payments, add payment account, report own card lost/stolen, report AU cards lost/stolen, remove AUs, pause cards, dispute transactions, gain account info, request balance/available credit, sign up for autopay, redeem rewards, request transaction exemption. CANNOT close account.\nAuthorized User can: report own card lost/stolen, pause own card, dispute own card transactions, gain account info, request own balance/available credit. Cannot make payments, add AUs, close account, redeem rewards.` },
  { name: "Application Support & Inquiry Guide", tags: ["application","apply","approval","denied","manual review","credit limit","APR","reapply","mobile app","dashboard"], content: `APPLICATION SUPPORT & INQUIRY GUIDE - IBCC\n\nAPPLICATION FLOW:\n1. Customer navigates to Lending Tab in QBO > Credit Card Offers > Learn More\n2. Enter Business Revenue and Incorporation Year\n3. Review auto-filled Company Information (can edit)\n4. Identity verification if needed (selfie + government ID)\n5. Upload additional documents if requested\n6. If credit frozen: contact Experian to lift restrictions\n\nDECISION OUTCOMES:\n- Auto Approve: Account provisioned immediately. Customer gets Welcome Email (no acceptance offer needed).\n- Auto Denied: Customer receives Adverse Action Notice (AAN) with denial reason.\n- Manual Review: Email sent with secure link to upload documents. Must complete within 30 days.\n\nPRODUCT ACCEPTANCE FLOW (Manual Review approvals):\n- Credit Acceptance Offer emailed. Valid 30 days. Customer clicks 'Accept Your Card'.\n- Then: Add virtual card to wallet > Add Authorized User (optional) > Set up Autopay (optional) > Order physical card (optional) > Redirected to dashboard\n\nFAQs:\n- Application status Approved: Look up in Admin Portal, assist\n- Application status In Process: Inform 30-day lifecycle, check for document needs\n- Application status Denied: Email sent with denial info. Based on credit score, DTI. No exact details available.\n- Why provide ID? Identity verification and fraud protection\n- Higher credit limit? Cannot modify offer once extended. Can reapply in 30 days, no guarantee.\n- Lower APR? Cannot decrease assigned APR.\n- When reapply? 30-day waiting period\n- Prequalified but declined? Prequalification does not guarantee approval.\n- Hard credit pull? Soft pull only.\n- How long to accept offer? 30 days (manual review). Auto approve gets welcome email instead.\n\nMOBILE APP DOWNLOAD:\n- Search 'Intuit Business Credit Card' in app store\n- After download: open app > tap Enter > phone auto-populates > Continue > optional passkey setup\n\nACCESSING VIA QBO:\n- Login to QBO > waffle icon > Lending > Credit Cards > Go to dashboard (card.intuit.com)\n\nMOBILE APP ONLY (not available on web dashboard):\n- Disputes (self-service), Adding/removing Authorized Users, Redeeming Rewards, Requesting first physical card` },
  { name: "Caller Validation Procedure", tags: ["validation","verify","identity","inbound","outbound","greeting","third party","business name"], content: `CALLER VALIDATION PROCEDURE - IBCC\n\nCALL GREETING (verbatim):\n"Thank you for contacting the Intuit Business Credit Card, my name is [Agent First Name]. How may I help you today?"\nNote: No call monitoring/recording disclosure required.\n\nCALL CLOSING:\n"Thank you for calling the Intuit Business Credit Card."\n\nCORE RULES:\n- Zero-Access Policy: Validate BEFORE accessing any account details\n- No Hinting: Never provide partial info to help caller guess\n- Late Additions: Anyone joining mid-call must be validated immediately\n- Multiple Accounts: Validate for each separate account\n\nINBOUND - ACCOUNT OWNER (4 variables required):\n1. Full Name as it appears on account (including suffixes)\n2. Business Name\n3. Phone Number\n4. Date of Birth OR Email Address\nException: If phone cannot be verified, BOTH DOB and Email must be provided.\nException: If business name shows as owner's first/last name, say: "In our records we sometimes list the business owner's first and last name in place of the business name. Can you confirm the owner's first and last name?" Advise we are working to resolve this.\n\nINBOUND - AUTHORIZED USER (4 variables required):\n1. Account Owner's Full Name\n2. Authorized User's Full Name\n3. Business Name\nAND one of: Primary Phone Number on account / Business Address / Account Owner's DOB / Last 4 digits of AU's assigned PAN\n\nOUTBOUND - ACCOUNT OWNER (4 variables required):\nSame as inbound owner.\n\nOUTBOUND - AUTHORIZED USER (4 variables required):\n1. AU first and last name\n2. Account Owner's first and last name\n3. Business Name\nAND one of: primary phone, business address, owner's DOB, last 4 of AU PAN\n\nFAILED VERIFICATION: Provide general info only + open fraud review ticket.\n\nINTERNAL TRANSFERS: Re-validation not required if already validated. Ask transferring agent what was validated and document.\n\nSTEPS TO VALIDATE:\n1. Search in Admin by phone number via Amazon Connect\n2. Validate per Section 6 requirements\n3. Address reason for call\n4. Ask if additional questions\n5. End call with branding\n6. Navigate to Notes tab in Admin Portal > click Add > detail the call > Save memo\n\nTHIRD PARTY CALLERS:\n- Cannot discuss account-specific info with third parties\n- Approved language: "I appreciate you reaching out. Unfortunately, we are unable to discuss any account-specific information with a third party. To protect the security and privacy of the account, we can only speak with the Account Owner or an authorized contact listed on the account. I'd encourage you to have the Account Owner or Account Administrator give us a call directly so we can assist them. Is there anything general I can help you with today?"` },
  { name: "Card Management: Replacement, Activation and Freezing", tags: ["card","replace","activate","freeze","lost","stolen","physical","virtual","AU card","international"], content: `CARD MANAGEMENT - IBCC\n\nCARD ELIGIBILITY:\n- Account must be Active and not delinquent to receive any card\n- Virtual card available immediately upon approval\n- Physical card: up to 10 business days via USPS, no tracking, cannot ship to PO Box\n\nCARD TYPES:\n- Account Owner: METAL card\n- Authorized Users: PLASTIC card\n\nFIRST PHYSICAL CARD: Must be self-serviced through mobile app. Agents CANNOT place first order in Admin Portal.\n\nACCOUNT OWNER: Can order/replace their own card and AU cards. To order/replace AU physical card = must call in.\nAUTHORIZED USER: Can replace their own virtual or physical cards via mobile app or phone. Cannot order/replace cards for other users.\n\nCARD ACTIVATION IN ADMIN PORTAL:\n1. Pull up account\n2. Validate caller\n3. Locate card - confirm last 4 digits and cardholder name\n4. Request customer verify card details (name, card type, last 4)\n5. Click 'Activate Card'\n6. Inform card is active; can add to mobile wallet\n7. Brand call, disconnect\n8. Update Salesforce, assign Tier-1 Closed, add Admin note\nNote: Cannot activate on web dashboard\n\nREPLACEMENT RULES:\n- 15-Day Rule (Physical only): Must wait 15 calendar days if card not received\n- Immediate reorder exceptions: Damaged, sent to wrong address, stolen after activation\n\nCARD REPLACEMENT IN ADMIN PORTAL:\n1. Pull up account\n2. Validate caller\n3. Confirm reason:\n   Lost/Stolen: Verify Active > step 4\n   Never Received <15 days: Ask caller to wait > step 11\n   Never Received >15 days: step 4\n   Damaged/Activation Issue: Verify Active > step 4\n   Found by 3rd Party: Do NOT disclose account info. Get printed name + last 4. Ask to destroy card. Assign to Tier-3.\n   Name Change: Assign to Tier-3\n4. Locate card in Admin Portal > Profile tab > search name > verify last 4 + format\n5. If physical card Pending: activate it first (step 6), then proceed\n6. Activate card first if needed\n7. Click 'Replace' (verify last 4, name, card type)\n8. Select replacement reason\n9. Inform: virtual = immediate; physical = 10 business days\n10. If lost/stolen: check for unauthorized transactions. If found, initiate dispute.\n11. Brand call, disconnect\n12-14. Update Salesforce, assign Tier-1 Closed, add Admin note\n\nFREEZE/UNFREEZE IN ADMIN PORTAL:\n1. Pull up account\n2. Validate\n3. Confirm cardholder name + card type > navigate to Freeze/Unfreeze sub-tab > click button\n4. Refresh to verify status updated\n5-8. Brand/disconnect, update Salesforce, assign Tier-1 Closed, add Admin note\n\nINTERNATIONAL TRANSACTIONS:\n- Must be manually enabled; Account Owner only (AUs cannot modify)\n- Mobile: Login > Profile > Your Card > International Usage toggle\n- Online: Login > Profile > Your Card > International Usage\n\nADDING AU (Mobile App only):\n1. Login > Your cards > '+' icon\n2. Enter: First Name, Last Name, Phone, DOB, Credit Limit\n3. Check permission box > Submit > Send invite > manually tap Send\n\nREMOVING AU (Mobile App only):\n1. Login > Your cards > select AU image > AU profile\n2. Scroll to bottom > 'Remove User' > Yes to confirm` },
  { name: "Customer-Initiated Account Closure Procedure", tags: ["close","closure","cancel account","rewards forfeited","suspended closure","credit balance refund"], content: `CUSTOMER-INITIATED ACCOUNT CLOSURE - IBCC\n\nAUTHORIZATION:\n- ONLY account owner can close an account (phone or in writing)\n- Administrators/Authorized Users CANNOT close an account\n\nKEY INFO TO ADVISE CUSTOMER:\n- Unredeemed rewards FORFEITED - must redeem via mobile app first\n- Charging privileges suspended including recurring transactions\n- AUs will also lose all charging privileges\n- Once closed, CANNOT be reopened\n- 30-day waiting period before reapplying\n\nCLOSURE PROCEDURE:\n1. Pull up account\n2. Validate caller\n3. Email: from email of record = step 10; not from email of record = send Unable to Assist template\n4. Express regret\n5. Ask clarifying questions about reason\n6. Restate/confirm request and reason\n7. Advise: cannot reopen, 30-day reapplication period\n8. READ VERBATIM: "Your account will now be closed. Please destroy any physical cards associated with this account. You will also want to cancel any recurring charges associated with your account. If you have an account balance, you are still responsible for the existing balance, including unposted transactions and any accrued interest or fees. Interest will continue to accrue on any unpaid balance in accordance with your cardholder agreement. You will continue to receive monthly statements until the account balance is paid in full and you are still responsible for making the monthly minimum payment on the account per the cardholder agreement. In addition you will forfeit any rewards on the account that have not been redeemed." Ensure customer agrees.\n9. Click pencil next to 'Status' section\n10. Status > Closed, Reason > Customer_Initiated\n11. Inform owner account is now closed\n12. Escalate to IBCC Servicing - Tier 2 queue\n13. Brand call, disconnect\n14. Update Salesforce, transfer to Tier-2\n15. Add detailed Admin note using Case Note Template\n\nSUSPENDED ACCOUNT CLOSURE: YES - can close even if Suspended (Generic Restriction, 1st/3rd Party Fraud). Get reason, document in memo, notify Fraud team.\n\nCREDIT BALANCE AT CLOSURE: Escalate to Tier-2 for refund. Tell customer: refund via ACH. Check refund NOT offered.` },
  { name: "Frequently Asked Questions", tags: ["FAQ","interest","rewards","statement balance","minimum payment","pending","reapply","annual fee"], content: `IBCC FREQUENTLY ASKED QUESTIONS\n\nPRODUCT: Business credit card issued by WebBank. Auto-syncs with QuickBooks. 5% cash back Intuit, 2% all other. $300 sign-up bonus (spend $3K in 3 months). No annual fee. Soft pull only. Unlimited AUs.\n\nINTEREST:\n- Avoid interest: Pay statement balance in full by due date every month\n- Still have interest after paying full balance: Interest charged on unpaid portion of PREVIOUS statement's balance. Also accrues daily on new purchases from transaction date.\n- Stop interest charges: Pay TWO consecutive statement balances to fully resolve\n\nDISPUTES:\n- Won dispute: Provisional credit now permanent. No additional refund. Available credit restored.\n- No update after weeks: Review in progress. Email if more info needed. Decision emailed when reached.\n- Merchant issued refund after dispute: If pending = can withdraw. If decisioned = resolved in merchant's favor, rebill applied.\n- Lost dispute: Generally final. Can request merchant evidence or submit new evidence by replying to dispute email.\n- Pending charge - can I dispute? No. Wait until settled. If unrecognized, replace card now.\n\nSTATEMENTS:\n- Statement balance: Total owed at end of billing cycle to avoid interest\n- Current balance: Real-time (includes new activity since cycle closed)\n- Minimum payment due: Amount required to keep account active and in good standing\n- Generated: Day after billing cycle ends\n- Where to view: Mobile app or online dashboard only (not sent via email or paper)\n\nPAYMENTS:\n- Cannot pay with debit card. Use ACH (linked bank), check via USPS, or wire transfer.\n- Cannot cancel payment in processing. Customer contacts bank for stop-payment.\n- Cannot change due date. System does not allow it.\n- Pay while suspended? Yes - does not guarantee suspension lifted.\n- Residual interest: After full payoff, may still see small interest on next statement.\n\nAPPLICATION:\n- Approved but want higher limit/lower APR: Cannot change offer. Reapply in 30 days, no guarantee.\n- Declined: 30 days from decision date before reapplying.\n- Prequalified but declined: Approval depends on full credit review. Prequalification not a guarantee.` },
  { name: "Identifying and Managing Suspicious Callers & Accounts on Hold", tags: ["suspicious","ATO","account takeover","fraud","generic restricted","first party","third party","enhanced validation","self payment"], content: `SUSPICIOUS CALLERS & ACCOUNTS ON HOLD - IBCC\n\nUSE FOR:\n- Scenario A: Suspicious caller (cannot validate or exhibits fraud behaviors)\n- Scenario B: Reported ATO or Identity Theft\n- Scenario C: Account already in suspended status\n\nSUSPICIOUS CALLER INDICATORS:\n1. Unable to validate most/all info\n2. Probing for info/asking for hints\n3. Multiple incorrect answers before correct one\n4. Asking to repeat questions, stalling\n5. Long pauses between questions\n6. Hearing typing/whispering/paper shuffling in background\n7. Multiple calls in short period\n8. Not receiving mail/emails to info of record\n9. Acquaintance interrupting or not allowing caller to speak\n10. Recognizing a voice that called with different name\n11. Abruptly ending call when asked to validate\n\nENHANCED VALIDATION (ask exactly 3 questions, do not cycle through for 3 correct):\n- DOB or Email (whichever not used in initial verification)\n- Credit Limit\n- Amount of Last Transaction\n- AU Phone Number (verify against Teams tab)\n- Account Owner Last Payment Amount\nIf passed but still suspicious: proceed, then assign to IBCC Risk Verifications Queue\nIf failed: general info only > assign to IBCC Risk Verification queue > add detailed note\n\nATO PROCEDURE:\n1. Express empathy, prioritize account security\n2. Validate caller\n3. Brief hold - review all account memos\n4. If validated: assist + document\n5. ATO probing questions:\n   - What led you to believe account was accessed?\n   - Checked with family/associates with QBO admin access?\n   - When did you last log in successfully?\n   - Any suspicious texts/emails/calls with links? (forward to fraud@intuit.com)\n   - Shared password or security codes with anyone?\n   - Still have physical card? Mail delivery issues?\n   - Unusual mobile service issues (SIM swap check)?\n6. Inform account will be suspended while reviewed\n7. Brand call, disconnect\n8. Escalate to Tier-2 (Tier-1 CANNOT change to Generic Restricted)\n\nUNAUTHORIZED ACCOUNT OPENING:\nProbing questions:\n- How did you learn the account existed?\n- Other unauthorized accounts on credit report?\n- Filed police report or FTC Identity Theft Report? (If yes: cardsupport@intuit.com)\n- Lost wallet/license/SSN card?\n- Anyone with access to personal info or mail? (ask sensitively)\n- Best email for follow-up?\nEscalate to Tier-2 after documenting.\n\nSUSPENDED ACCOUNT (Scenario C):\nNEVER say "Fraud Status" or "Fraud Investigation". Always say "temporary hold" or "currently restricted pending standard administrative review".\n1. Validate\n2. Brief hold - review memos for INTERNAL NOTES / PUBLIC DISCLOSURE / CUSTOMER ASK sections\n3. Share only PUBLIC DISCLOSURE info. If no notes: advise account restricted pending review.\n4. Brand, disconnect\n5. Escalate to IBCC Risk Verification Queue\n\nSELF-PAYMENT (1st Party Fraud Suspended):\n- Prior to March 2, 2026: If valid payment after suspension or transaction reversed = suspension removed\n- After March 2, 2026: Customer receives email. Must make valid minimum payment. 7-day wait after payment. Additional self-payments may result in account closure.\n- Tier-1 CANNOT change account status.` },
  { name: "Payment Procedures and Payment Inquiries", tags: ["payment","autopay","ACH","check","bill pay","cancel payment","returned","duplicate","processing","OTB","available credit"], content: `PAYMENT PROCEDURES - IBCC\n\nIMPORTANT:\n- Only Account Owners and Account Administrators can schedule a payment\n- Third party CANNOT make payments with a Front Line agent\n- ONE-TIME PAYMENT OVER THE PHONE IS CURRENTLY UNAVAILABLE (as of 02/11/2026)\n\nPAYMENT PROCESSING:\n- Posting: Posts immediately, reduces current balance right away\n- Available Credit (OTB): Up to 5 business days to update\n- Weekend/Holiday: Processing starts next business day; 5-day clock starts then\n\nPAYMENT METHODS:\n- Auto-Pay (Mobile/Dashboard): Auto-processes on due date. Cancel must be 3 days before.\n- One-Time Payment (Mobile/Dashboard): After 10 PM ET or non-business day = next business day. Due by 11:59 PM ET.\n- One-Time Payment Phone with Agent: CURRENTLY UNAVAILABLE (02/11/2026)\n- Check: By 5 PM EST = credited same day. After = next day. Allow 10 business days. Address: Intuit Financing Inc, PO Box 842978, Dallas, Texas 75284-2978\n- Bill Pay: Not accepted via ACH. Bank generates paper check. Same address as above.\n\nPHONE PAYMENT DISCLOSURE (verbatim, for when feature returns):\n"This is to confirm that on [today's date], you gave verbal authorization to have a one-time payment debited from the bank account ending in [last 4]. Do you agree?" (pause) "Do you authorize Intuit Business Credit Card to process this payment in the amount of $[amount]?"\n\nAUTOPAY DISCLOSURE (verbatim):\n"This is to confirm that on [date], you are authorizing recurring payments of [Statement Balance/Minimum Payment Due] to be debited from the bank account ending in [last 4]. These payments will automatically be drawn on [statement due date]. If you need to make changes, you will need to contact us at least 3 business days prior to the transaction date to modify the recurring payment. Do you agree?" (pause) "Do you authorize Intuit Business Credit Card to process this payment schedule in the amount of [Statement Balance/Minimum Payment Due]?"\n\nAUTOPAY CANCELLATION: Agents CANNOT cancel autopay. Customer must turn off in mobile app.\n\nCANCELLING SCHEDULED PAYMENTS:\n1. Validate\n2. Scheduled Payments sub-tab > locate payment > Cancel Payment under Actions column\n3. Delete Scheduled Payment window > Delete\nNote: Cannot cancel autopay or payments already processing\n\nMISSING PAYMENTS:\n- Check: Verify in Payments section. If cleared by bank but not showing, request front/back of check to cardsupport@intuit.com. Escalate Tier-2.\n- ACH: Verify scheduled at least 2 business days ago. If debited from bank, escalate Tier-2.\n- Bill Pay: Same as check process. Not accepted via ACH - bank issues paper check.\n- Incorrect Address: Check for other Intuit products. Escalate Tier-2.\n\nDUPLICATE/RETURNED:\n- Duplicate: Check Payments section. Cancel if possible. If processing, customer contacts bank.\n- Returned: Payments tab > Status column shows 'Returned'. Check for returned payment fee. Offer replacement payment if past due. Cannot determine reason - customer contacts bank.` },
  { name: "Phone Security Verification Process for IBCC Applications", tags: ["phone verification","PV","security verification","application","outbound","risk analyst","verification questions"], content: `PHONE SECURITY VERIFICATION (PV) - IBCC APPLICATIONS\n\nPURPOSE: Required for IBCC applications flagged for additional authentication.\n\nROLES:\n- Risk Operations Analysts (RA): Create/manage verification cases in Salesforce, make final application decision\n- Frontline Agents: Complete outbound PV calls, document, escalate to Risk Operations\n\nMake at least 2 attempts within 2 business days.\n\nCASE STATUS UPDATES:\n- 1st call Successful: Status Escalated, Sub-Status In Progress\n- 1st call Unsuccessful: Status Pending, Sub-Status Waiting Customer\n- 2nd call Successful: Status Escalated, Sub-Status In Progress\n- 2nd call Unsuccessful: Status Pending, Sub-Status Customer Update Not Received\n\nVERIFICATION QUESTIONS (ask 1 from each of 3 different categories):\nLOW: Age, Auto loan details, Previous employer, Previous address\nMEDIUM: Personal credit card (highest balance or most recent), City/state in prior year, Mortgage details\nHIGH: SSN digits, Business history, Capital product details, Student loan details\n\nOUTBOUND PROCEDURE:\n1. Locate oldest open case in IBCC Phone Security Verifications queue (work by Created Date)\n2. Initiate outbound call in Amazon Connect\n3. Greeting: "Hello, my name is [Agent Name] with the Intuit Business Card. Am I speaking with [First and Last Name]?"\n4. Advise additional information needed to process application\n5. Validate caller per Caller Validation Procedure\n6. Ask 3 verification questions (1 from each of 3 categories). RA may add more per Salesforce case.\n7. Thank applicant, advise decision arrives via email\n8. Document Q&A in Admin Portal AND Salesforce case\n9. Comment in Salesforce case comments (QB Capital view > Related > Case Comments > New)\n10. Leave case with Status Escalated, Sub-Status In Progress\n\nVoicemail: "Hello, this message is for [Name]. I'm calling from Intuit Business Card. Please give us a call back at your earliest convenience at 888-464-7840."\n3rd Party message: "Please have them return my call at 888-464-7840."\n\nINBOUND CALLBACK: Advise specialist will call back. Escalate new case to IBCC Phone Security Verifications queue, Status Open, Sub-Status In Process.\nMAX CALLBACKS: 1 per active case.` },
  { name: "Proactive Outreach for Suspicious Account Activity and Takeover Prevention", tags: ["proactive outreach","ATO prevention","welcome call","google sheet","outbound","takeover"], content: `PROACTIVE OUTREACH - ATO PREVENTION - IBCC\n\nOVERVIEW: Outbound 'Welcome Calls' to high-risk accounts flagged by Risk Team.\nSINGLE ATTEMPT per account only.\n\nPROCEDURE:\n1. Locate account in Admin Portal using realm number from Google Sheet\n2. Review account notes - EXCLUDE from call list if customer already reported unauthorized account opening\n3. Get phone from Column C of Google Sheet. Introduce: "Hello, my name is [Name] and I'm calling from Intuit. May I please speak with [Customer Name]?"\n4. Call outcomes:\n   - Customer confirms identity: "Before we get started I do have to inform you that this call may be monitored or recorded for quality assurance." Go to step 5.\n   - 3rd party who knows owner: "Could you tell [name] that Intuit is calling regarding a business matter and that we would appreciate a call back at 888-464-7840"\n   - Wrong number: "I apologize for the interruption. I will update our records to ensure you aren't contacted again. Have a great day."\n   - Voicemail/no answer: "This message is for [First and Last Name]. This is Intuit calling regarding a personal business matter. Could you please return our call at 888-464-7840? Thank you."\n5. SOFT QUESTIONS only (do not verify or disclose sensitive details until customer confirms awareness):\n   "Congratulations on your new IBCC account! We're excited to have you with us. I'm just calling to make sure you're enjoying the card so far and to see if you have any questions or feedback to share?"\n6. If customer CONFIRMS AWARENESS: proceed with call + validate before sharing sensitive details\n   If DENIES KNOWLEDGE: Do NOT provide account info. Ask:\n   - "Is there anyone else in your household or business partner who might have initiated this application?"\n   - "Do you recall looking into the IBCC lately or starting an application?"\n   If customer needs to check with partner: place protective hold (Generic Restricted via Suspicious Callers SOP)\n   If still unfamiliar: place protective hold, advise account forwarded to specialty team\n7. Update ATO Google Sheet\n8. Add Admin note` },
  { name: "Rewards Overview", tags: ["rewards","cash back","5%","2%","redeem","statement credit","spend and get","bonus","negative rewards","promotional offers","mailchimp","turbotax"], content: `REWARDS OVERVIEW - IBCC\n\nPROGRAM: Offered by QuickBooks Capital. Auto-enrolled when account opened.\nRewards earned and posted to Card Account - not individual employee cards.\n\nCASH BACK RATES:\n- 5% on Intuit Purchases (Intuit software/subscriptions)\n- 2% on all other eligible everyday purchases\n- Posted after transaction settles (not for pending)\n\n5% DOES NOT APPLY TO: QuickBooks Payments merchant fees, QBO invoice payment fees, QB Term Loan/Line of Credit, Credit Karma, Intuit Enterprise Suite, software purchased via accountant\n\nREDEMPTION RULES:\n- Only account owner or administrator may redeem (via mobile app only)\n- Only redeemable as statement credit\n- Minimum $0.01 required\n- Cannot partially redeem - entire balance redeemed at once\n- Account must be Active (Good Standing)\n- Reduces balance but does NOT satisfy minimum payment due\n- If reduces balance to $0.00, no minimum payment required that cycle\n- Unredeemed rewards FORFEITED at account closure\n- Redemptions are FINAL and cannot be reversed\n\nSPEND AND GET BONUS: Spend $3,000 in first 90 days = $300 statement credit within 6-8 weeks.\n- Account must be open and in Good Standing\n- NO communication sent when applied. Shows in Admin Portal Transactions tab as 'welcome Bonus'. In app shows as 'credit'.\n- Eligibility revoked if: returned payment outstanding, fraudulent activity suspected\n\nNEGATIVE REWARDS: If rewards earned on returned/disputed (resolved in owner's favor) purchase, rewards deducted. Future rewards offset negative balance.\n\nREDEEMING IN APP:\n1. Open app > scroll to bottom of dashboard > tap arrow in Rewards section\n2. Redeem screen: amount non-adjustable, must redeem in full\n3. Select 'Redeem' - NO confirmation prompt - immediately finalized\n\nVIEWING IN ADMIN PORTAL:\n- Transactions tab > select settled transaction > Reward % and amount on right side\n- Redeemed rewards: RED FONT in Amount column, labeled 'Cashback' in Merchant Name field\n\nESCALATE TO TIER-2 IF: Negative rewards calculation issues, accrual issues, redemption issues (cannot redeem in app), data discrepancies between Admin Portal and app.\n\nPROMOTIONAL OFFERS (all require active IBCC, one-time use, 90-day window unless noted):\n- 25% Off QB Expert Bookkeeping: Up to $200, discount at checkout, active QBO + IBCC payment, accountants NOT eligible\n- 75% Off QB Live Expert Assist (3 mo): Up to $225, discount at checkout, active QBO + IBCC payment, accountants excluded\n- $100 Statement Credit QB Checking: QB Checking opened AND funded AFTER IBCC opening, within 90 days\n- Free TurboTax Live Business Filing: Within 12 months, business returns only (Schedule C, S-Corp, Partnerships)\n- Free Mailchimp Standard 12 months: Up to $540, new Mailchimp users only, IBCC as payment, $45/month credits, cancel = lose remaining credits` },
  { name: "Statement Overview", tags: ["statement","billing","minimum payment","due date","new balance","paperless","resend","statement ready"], content: `STATEMENT OVERVIEW - IBCC\n\nKEY FACTS:\n- IBCC is PAPERLESS - NO paper statements offered\n- Statements generated the day after billing cycle ends\n- Account owner receives email notification when available\n- Customer must login to mobile app or dashboard to view/download\n- We do NOT send billing statements via email\n\nSTATEMENT DEFINITIONS:\n- Minimum Payment Due: Greater of (1) 1% of new statement balance + periodic interest + late fees, OR (2) $40. If statement balance < $40, MPD = statement balance.\n- Past Due: Portion of MPD not received by due date\n- New Balance: Previous balance + purchases + fees + interest - payments - credits\n- Current Balance: Real-time (includes new activity since cycle closed)\n- Statement Balance: Total at end of billing cycle\n\nACCESSING STATEMENTS - DASHBOARD:\n1. card.intuit.com > Profile (left-hand nav)\n2. Under 'Intuit Details' > Statements\n3. Select Download icon next to desired statement\n\nACCESSING STATEMENTS - MOBILE APP:\n1. Login > Profile Icon (initials, upper right)\n2. Scroll to 'Your Card' > Statements\n3. Select month > save or print using device's native functions\n\nRESENDING 'STATEMENT READY' EMAIL:\n1. Navigate to Comms tab in Admin Portal\n2. Locate 'Your Statement for Intuit Credit Card is Ready' for relevant month\n3. Click Resend button (upper left)\n4. Verify delivery in Comms tab - check email name and Date Sent timestamp` },
  { name: "Transaction Dispute Intake Procedure", tags: ["dispute","chargeback","raise dispute","provisional credit","settled","pending","unauthorized","60 days","intake"], content: `TRANSACTION DISPUTE INTAKE PROCEDURE - IBCC\n\nCHANNELS: Mobile App (self-service), Phone (agent-assisted). Web Dashboard NOT supported.\n\nELIGIBILITY:\n- Account Owner/Administrator: Can dispute ANY transaction on account (including AUs)\n- Authorized User: Can only dispute transactions on cards issued in their name\n- Must be SETTLED (not Pending)\n- Must be within 60 days of appearing on billing statement (system enforces - do not manually calculate)\n\nDISPUTE INTAKE IN ADMIN PORTAL:\n1. Pull up account, validate caller\n2. Ask for: merchant name, amount, in-person or online\n3. Navigate to Transactions tab, locate transaction\n4. Use Transaction Dispute Intake Questions to categorize claim\n5. Confirm eligibility and dispute reason\n6. Click transaction > click blue 'Raise Dispute' button\n7. 'Report an Issue' pop-up: select dispute reason > Continue\n8. Enter responses from Intake Questions\n9. BEFORE submitting, disclose:\n   - Provisional Credit: Temporary credit applied immediately. NOT available for spending during investigation.\n   - Confirmation email will be sent to registered email\n   - All updates/decisions via email - monitor inbox\n10. READ VERBATIM: "You certify that all of the information in this claim is true and accurate to the best of your knowledge. You understand that any misrepresentation may render your claim invalid and that you have read and acknowledged the Intuit Business Card Cardholder Agreement." Get verbal 'Yes' or 'Agree'.\n11. Review confirmation window > Submit\n12. Verify in Disputes tab: correct date, merchant, amount, status 'Pending'\n13. Verify email triggered in Comms tab: 'You've Initiated a Dispute on Intuit Business Credit Card'\n14. Brand call, disconnect\n15. Assign to IBCC Transaction Disputes queue\n16. Add Admin note\n\nDISPUTE VIA MOBILE APP:\n1. Login > Profile Icon > Recent Transactions > See All\n2. Select transaction > Report an Issue\n3. Select dispute reason (agent should NOT decide the reason)\n4. Enter Correct Amount > date contacted merchant (required) > What Happened summary\n5. Review Summary > check validation box > Submit Dispute\nWithdraw option only available while on same screen; otherwise must call agent.\nOnce withdrawn, SAME TRANSACTION CANNOT be disputed again.` },
  { name: "Transaction Dispute Intake Questions", tags: ["dispute questions","fraud lost stolen","goods not received","not as described","defective","duplicate charge","wrong amount","refund not processed"], content: `TRANSACTION DISPUTE INTAKE QUESTIONS - IBCC\n\nNote: Answers go in account notations AND Salesforce case.\n\nFRAUD/COMPROMISED/STOLEN/LOST CARD:\n- Do you have possession of the card?\n  If NO: When/how lost? Recognize the merchant? Given anyone permission to use card? (If yes: who, why, description)\nAgent notation must include: Merchant name, date, amount, last 4 of card\n\nGOODS/SERVICES NOT RECEIVED:\n- Have you attempted to contact the merchant?\n  If NO: Advise must contact merchant first before disputing.\n  If YES: When/how? Specific description of goods/services? Expected delivery date? Tracking number/confirmation?\n\nNOT AS DESCRIBED/DEFECTIVE MERCHANDISE:\n- Have you attempted to contact the merchant?\n  If NO: Advise must contact merchant first.\n  If YES: Merchant response? Description of ordered vs. received? Cancellation/return date? Tracking for returned goods?\n\nREFUND CREDIT NOT PROCESSED/CANCELLED SERVICES:\n- Have you attempted to contact the merchant?\n  If NO: Advise must contact merchant first.\n  If YES: Date services cancelled or goods returned? Tracking for returned goods?\n\nDUPLICATE CHARGE/PAID BY OTHER MEANS:\n- Have you attempted to contact the merchant?\n  If NO: Advise must contact merchant first.\n  If YES: When contacted and response? Date/time of valid transaction? Date and amount of transaction to dispute? Alternate payment method? Proof (bank statement, receipt)?\n\nWRONG AMOUNT:\n- Have you attempted to contact the merchant?\n  If NO: Advise must contact merchant first.\n  If YES: When contacted and response? Date and amount of disputed transaction? Expected amount? Proof (receipt/invoice)?\n\nNOTE FOR ALL NON-FRAUD TYPES: If customer has NOT contacted merchant, advise: "Prior to disputing a transaction an attempt must be made to resolve the issue directly with the merchant. Please attempt to reach out to the merchant for direct resolution. If after contacting the merchant a dispute is still needed, please give us a call back with details of your attempt to contact the merchant."` },
  { name: "Transaction Exemption Procedure", tags: ["exemption","declined","STIP","transaction decline","prohibited","card network","same day"], content: `TRANSACTION EXEMPTION PROCEDURE - IBCC\n\nFrontline agents: determine eligibility, set expectations, escalate. Agents do NOT approve or deny.\nExemptions NOT guaranteed. Apply only to specific declined transaction. Future transactions CANNOT be pre-approved.\n\nWHO CAN REQUEST:\n- Account Owner & Administrator: any active card on account\n- Authorized Users: only their own assigned active card\n\nPROHIBITED (NOT eligible for exemption regardless of decline reason):\n- Cash advances/cash equivalents (P2P transfers, balance transfers, gift cards, prepaid cards, wire transfers)\n- Certain specialty retailers (dating/escort, digital goods, games)\n- Gambling transactions\n- Securities, bonds, broker/dealer transactions\n\nONLY 'STIP' DECLINE REASON IS ELIGIBLE FOR EXEMPTION.\nNot eligible: account status inactive, insufficient funds, card not active, address mismatch, incorrect CVC, wrong expiration date, prohibited merchant category, AU card frozen\n\nPROCEDURE:\n1. Locate account, validate caller\n2. Locate declined transaction in Transaction tab\n3. Check if prohibited category. If yes, advise and end.\n4. Confirm decline reason. Only STIP eligible. If not, end.\n5. Confirm SAME DAY as attempted transaction. Cannot request for past transactions.\n6. If eligible, advise: "Transaction Exemptions are not guaranteed. Please re-attempt the transaction after 1 hour has elapsed. If the exemption is not granted and you continue to experience a decline, we recommend using an alternative payment method to complete the transaction."\n7. Notate: Transaction Date, Merchant Name, Transaction Amount, What customer was attempting to purchase\n8. Create Salesforce case - Subject: 'Transaction Exemption Request' with same info\n9. Escalate to IBCC Transaction Exemption queue. Risk Management Analyst investigates and closes case.\n10. If not eligible: notate all info. End Procedure.` },
  { name: "Translator Line Procedure", tags: ["translator","language","interpreter","language line","non-english","Spanish"], content: `TRANSLATOR LINE - IBCC\n\nPartner: Language Line Solutions (for all non-English voice calls)\nPhone: 800-367-9559\nClient ID: 744324\nAccess Code: 33105\n\nPROCEDURE:\n1. If customer requests interpreter: ask permission for brief hold\n2. Place customer on hold\n3. Select Quick Connects, dial 800-367-9559\n4. Provide: Client ID 744324, language needed, Access Code 33105\n5. Remain on line until connected with interpreter\n6. Once connected, read disclosure: "Hello my name is [name] and I am calling from the Intuit Business Card. Before we get started I do have to inform you that this call may be monitored or recorded for quality assurance."\n7. Ask interpreter for first name and number only\n8. Brief interpreter: "I need assistance from the Translator Line for a [Language] speaker to handle an inquiry related to the Intuit Business Card. Please stand by to facilitate the conversation"\n9. Add customer to three-way call. Repeat greeting. Begin Caller Validation.\n10. Best practices:\n    - Speak in short, clear sentences; one question at a time\n    - Remain silent while interpreter and customer speak\n    - Document responses exactly as interpreter relays - never guess\n    - NEVER disconnect yourself or transfer customer directly to interpreter\n    - Remain patient - interpretation takes longer\n11. Follow standard procedure for customer's specific issue\n12. Before ending: inform interpreter call is now ended, brand the call, thank interpreter: "Thank you, we're all set. You may disconnect now."\n13. Add note to Admin Portal using Case Note Template` },
  { name: "Updating Permissions and Account Information", tags: ["name change","address change","phone change","DOB","SSN","marketing","do not call","paper statement","e-consent","econsent","unsubscribe"], content: `UPDATING PERMISSIONS AND ACCOUNT INFORMATION - IBCC\n\nPROFILE CHANGES (Risk Dept only makes changes in Admin Portal):\nChanges requiring Risk review: Social Security Number, Date of Birth, Phone Number, Address\nProcess: Validate > gather info > escalate to Tier-2 with: Account ID, name, what change, why, new info\n\nDO NOT CALL DIRECTIVES:\n- Email requests: send 'Unable to Assist via Email' template (regardless of email source)\n- Gather info, escalate to Tier-2\n\nPAPER STATEMENTS:\n- IBCC does NOT offer paper statements\n- Direct customer to view/download online or in mobile app\n- If insistent: escalate to Tier-2\n\nNAME CHANGE - AUTHORIZED USER:\n- AU must request through Account Owner\n- Owner removes AU via mobile app, re-adds with correct name (triggers new SMS invite)\n\nNAME CHANGE - ACCOUNT OWNER:\nMinor (handle immediately, Tier-2 for processing):\n- Transposition of 1-2 letters only (e.g., Hokpins to Hopkins)\n- Inverted first/last names\n\nMajor (requires documentation):\n- Suffix adjustment (Jr., Sr., III)\n- Correction exceeding 2 characters\n- Marriage, divorce, legal gender affirmation, naturalization, reversion to maiden name\n\nDOCUMENTATION for Major Name Changes:\n- Suffix/Significant Correction: Valid government-issued ID\n- Marriage: Marriage Certificate OR updated government ID\n- Divorce: Divorce Decree (name restoration section) or updated SSN card\n- Legal Identity/Gender Affirmation: Court order + updated government ID\n- Naturalization: Certificate of Naturalization or updated SSN card or updated ID\n- Reversion to Maiden Without Divorce: SSN card update or valid ID\nMail documents to: Intuit Financing Inc, PO Box 842978, Dallas, Texas 75284-2978\n\nREVOKING E-CONSENT:\nREAD VERBATIM: "If you withdraw your consent to receive credit card communication electronically, you will remain responsible for the payments and remaining balance on the account even if you do not receive your monthly statement via electronic delivery. Please confirm you understand that you are still responsible for any balance on the account?"\nIf owner wants to revoke: escalate to Tier-2\n\nUNSUBSCRIBE MARKETING EMAILS:\n1. Validate\n2. Confirm: "I can go ahead and complete that for you, just to confirm, you'd like me to opt you out of marketing phone call communications, correct?"\n3. Go to Marketing Preferences Center (data-privacy.app.intuit.com/preferences) and complete\n4. Assign Tier-1, Status Closed. Add Admin note.` }
];

const SCRIPTS = [
  { label: "Call Opening", tag: "greeting", text: '"Thank you for contacting the Intuit Business Credit Card, my name is [Agent First Name]. How may I help you today?"' },
  { label: "Call Closing", tag: "closing", text: '"Thank you for calling the Intuit Business Credit Card."' },
  { label: "Business Name Exception", tag: "biz name", text: '"Thank you for confirming. In our records, we sometimes list the business owner\'s first and last name in place of the business name. Can you please confirm the owner\'s first and last name?"' },
  { label: "Third Party Caller", tag: "3rd party", text: '"I appreciate you reaching out. Unfortunately, we are unable to discuss any account-specific information with a third party. To protect the security and privacy of the account, we can only speak with the Account Owner or an authorized contact listed on the account. I\'d encourage you to have the Account Owner or Account Administrator give us a call directly so we can assist them. Is there anything general I can help you with today?"' },
  { label: "Account Closure Verbatim", tag: "closure", text: '"Your account will now be closed. Please destroy any physical cards associated with this account. You will also want to cancel any recurring charges associated with your account. If you have an account balance, you are still responsible for the existing balance, including unposted transactions and any accrued interest or fees. Interest will continue to accrue on any unpaid balance in accordance with your cardholder agreement. You will continue to receive monthly statements until the account balance is paid in full and you are still responsible for making the monthly minimum payment on the account per the cardholder agreement. In addition you will forfeit any rewards on the account that have not been redeemed."' },
  { label: "Phone Payment Disclosure", tag: "payment", text: '"This is to confirm that on [today\'s date], you gave verbal authorization to have a one-time payment debited from the bank account ending in [last 4]. Do you agree?" (pause) "Do you authorize Intuit Business Credit Card to process this payment in the amount of $[amount]?"' },
  { label: "Autopay Disclosure", tag: "autopay", text: '"This is to confirm that on [date], you are authorizing recurring payments of [Statement Balance/Minimum Payment Due] to be debited from the bank account ending in [last 4]. These payments will automatically be drawn on [statement due date]. If you need to make changes, you will need to contact us at least 3 business days prior to the transaction date to modify the recurring payment. Do you agree?" (pause) "Do you authorize Intuit Business Credit Card to process this payment schedule in the amount of [Statement Balance/Minimum Payment Due]?"' },
  { label: "Dispute Certification", tag: "dispute", text: '"You certify that all of the information in this claim is true and accurate to the best of your knowledge. You understand that any misrepresentation may render your claim invalid and that you have read and acknowledged the Intuit Business Card Cardholder Agreement."' },
  { label: "Suspended Account Script", tag: "suspended", text: 'NEVER say "Fraud Status" or "Fraud Investigation." Always say: "Your account is currently on a temporary hold pending a standard administrative review."' },
  { label: "E-Consent Revocation", tag: "econsent", text: '"If you withdraw your consent to receive credit card communication electronically, you will remain responsible for the payments and remaining balance on the account even if you do not receive your monthly statement via electronic delivery. Please confirm you understand that you are still responsible for any balance on the account?"' },
  { label: "Transaction Exemption Advisory", tag: "exemption", text: '"Transaction Exemptions are not guaranteed. Please re-attempt the transaction after 1 hour has elapsed. If the exemption is not granted and you continue to experience a decline, we recommend using an alternative payment method to complete the transaction."' },
  { label: "Translator Line Info", tag: "translator", text: 'Dial 800-367-9559 via Quick Connects. Client ID: 744324 | Access Code: 33105. Then: "Hello my name is [name] and I am calling from the Intuit Business Card. Before we get started I do have to inform you that this call may be monitored or recorded for quality assurance."' },
];

const SYSTEM_PROMPT = `You are an expert customer support assistant for the Intuit Business Credit Card (IBCC). Your role is to help support agents find procedures, policies, and step-by-step instructions quickly and accurately during live customer calls.

When answering:
- Be concise and direct — agents need fast answers during live calls
- When a procedure is involved, ALWAYS format it as a numbered step-by-step list
- Highlight critical warnings, verbatim scripts, or escalation points clearly
- If the docs don't cover something, say so clearly and suggest escalation
- Use plain language; avoid jargon
- Always end with "Need anything else on this?" to invite follow-up

The documents provided are the authoritative source. Do not invent procedures not found in the docs.`;

const NAV = [
  { id: "chat", label: "Chat", icon: "💬" },
  { id: "search", label: "Search", icon: "🔍" },
  { id: "browse", label: "Topics", icon: "📂" },
  { id: "scripts", label: "Scripts", icon: "📋" },
  { id: "docs", label: "Docs", icon: "📄" },
];

const CATEGORIES = [
  { label: "Caller Validation", icon: "🔐", q: "What are the exact validation requirements for an inbound account owner?" },
  { label: "Disputes & Chargebacks", icon: "⚖", q: "How do I initiate a transaction dispute for a customer?" },
  { label: "Payments & Billing", icon: "💳", q: "What payment methods are accepted and how do I process a payment?" },
  { label: "Account Management", icon: "👤", q: "What can an Administrator do vs an Authorized User?" },
  { label: "Fraud & Security", icon: "🔒", q: "How do I handle a suspected Account Takeover?" },
  { label: "Card Management", icon: "🪪", q: "How do I replace a lost or stolen card?" },
  { label: "Rewards", icon: "★", q: "How does the rewards program work and how do customers redeem?" },
  { label: "Account Closure", icon: "🚪", q: "What is the full procedure to close a customer account?" },
  { label: "Applications", icon: "📋", q: "What are the steps for handling an application inquiry?" },
  { label: "Statements", icon: "📄", q: "How do I help a customer access their statement?" },
  { label: "Account Tags & Statuses", icon: "🏷", q: "Explain the account tag and status system." },
  { label: "Suspicious Callers", icon: "⚠", q: "How do I handle a suspicious caller or a caller I cannot validate?" },
];

export default function AgentKB() {
  const [view, setView] = useState("chat");
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);
  const [searchQuery, setSearchQuery] = useState("");
  const [searchResults, setSearchResults] = useState([]);
  const [browseSearch, setBrowseSearch] = useState("");
  const [scriptFilter, setScriptFilter] = useState("");
  const [copiedIdx, setCopiedIdx] = useState(null);
  const chatEndRef = useRef();
  const inputRef = useRef();
  const searchRef = useRef();

  useEffect(() => { chatEndRef.current?.scrollIntoView({ behavior: "smooth" }); }, [messages]);

  useEffect(() => {
    if (view === "search") setTimeout(() => searchRef.current?.focus(), 50);
  }, [view]);

  const doSearch = (q) => {
    setSearchQuery(q);
    if (!q.trim()) { setSearchResults([]); return; }
    const lower = q.toLowerCase();
    const results = [];
    DOCS.forEach(doc => {
      const nameMatch = doc.name.toLowerCase().includes(lower);
      const tagMatch = doc.tags.some(t => t.toLowerCase().includes(lower));
      const contentLines = doc.content.split("\n").filter(l => l.toLowerCase().includes(lower));
      if (nameMatch || tagMatch || contentLines.length > 0) {
        results.push({ doc, nameMatch, tagMatch, snippets: contentLines.slice(0, 3) });
      }
    });
    setSearchResults(results);
  };

  const buildContext = () =>
    "\n\n--- IBCC KNOWLEDGE BASE DOCUMENTS ---\n" + DOCS.map(d => `[${d.name}]\n${d.content}`).join("\n\n---\n\n");

  const sendMessage = async (text) => {
    const msg = text || input.trim();
    if (!msg) return;
    setInput("");
    setView("chat");
    const newMsgs = [...messages, { role: "user", text: msg }];
    setMessages(newMsgs);
    setLoading(true);
    try {
      const res = await fetch("https://api.anthropic.com/v1/messages", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          model: "claude-sonnet-4-20250514",
          max_tokens: 1000,
          system: SYSTEM_PROMPT + buildContext(),
          messages: newMsgs.map(m => ({ role: m.role === "assistant" ? "assistant" : "user", content: m.text })),
        }),
      });
      const data = await res.json();
      const reply = data.content?.find(b => b.type === "text")?.text || "Sorry, I couldn't generate a response.";
      setMessages(m => [...m, { role: "assistant", text: reply }]);
    } catch {
      setMessages(m => [...m, { role: "assistant", text: "Connection error. Please try again." }]);
    }
    setLoading(false);
    setTimeout(() => inputRef.current?.focus(), 50);
  };

  const handleKey = (e) => { if (e.key === "Enter" && !e.shiftKey) { e.preventDefault(); sendMessage(); } };

  const copyScript = (text, idx) => {
    navigator.clipboard.writeText(text.replace(/^"|"$/g, "")).catch(() => {});
    setCopiedIdx(idx);
    setTimeout(() => setCopiedIdx(null), 1800);
  };

  const formatMsg = (text) => text.split("\n").map((line, i) => {
    if (/^\d+\.\s/.test(line)) return <div key={i} style={{ display: "flex", gap: 8, margin: "3px 0" }}><span style={{ color: "var(--color-text-secondary)", fontSize: 12, minWidth: 20, flexShrink: 0 }}>{line.match(/^\d+/)[0]}.</span><span style={{ fontSize: 13, lineHeight: 1.6 }}>{line.replace(/^\d+\.\s/, "")}</span></div>;
    if (/^[-•]\s/.test(line)) return <div key={i} style={{ display: "flex", gap: 6, margin: "2px 0", paddingLeft: 6 }}><span style={{ color: "var(--color-text-secondary)", fontSize: 11, minWidth: 12, flexShrink: 0, paddingTop: 2 }}>•</span><span style={{ fontSize: 13, lineHeight: 1.6 }}>{line.replace(/^[-•]\s/, "")}</span></div>;
    if (/^\*\*.+\*\*/.test(line.trim())) return <p key={i} style={{ fontWeight: 500, fontSize: 13, margin: "6px 0 2px" }}>{line.replace(/\*\*/g, "")}</p>;
    if (!line.trim()) return <div key={i} style={{ height: 5 }} />;
    return <p key={i} style={{ fontSize: 13, margin: "2px 0", lineHeight: 1.6 }}>{line}</p>;
  });

  const highlight = (text, q) => {
    if (!q) return text;
    const idx = text.toLowerCase().indexOf(q.toLowerCase());
    if (idx === -1) return text;
    const start = Math.max(0, idx - 30);
    const end = Math.min(text.length, idx + q.length + 60);
    const snippet = (start > 0 ? "…" : "") + text.slice(start, end) + (end < text.length ? "…" : "");
    return snippet;
  };

  const filteredScripts = SCRIPTS.filter(s => !scriptFilter || s.label.toLowerCase().includes(scriptFilter.toLowerCase()) || s.tag.toLowerCase().includes(scriptFilter.toLowerCase()));

  return (
    <div style={{ display: "flex", height: 660, background: "var(--color-background-primary)", border: "0.5px solid var(--color-border-tertiary)", borderRadius: "var(--border-radius-lg)", overflow: "hidden", fontFamily: "var(--font-sans)" }}>

      {/* Sidebar */}
      <div style={{ width: 200, borderRight: "0.5px solid var(--color-border-tertiary)", display: "flex", flexDirection: "column", background: "var(--color-background-secondary)", flexShrink: 0 }}>
        <div style={{ padding: "13px 14px 10px", borderBottom: "0.5px solid var(--color-border-tertiary)" }}>
          <div style={{ fontSize: 10, fontWeight: 500, color: "var(--color-text-tertiary)", letterSpacing: "0.06em", marginBottom: 2 }}>INTUIT IBCC</div>
          <div style={{ fontSize: 13, fontWeight: 500, color: "var(--color-text-primary)", lineHeight: 1.3 }}>Agent Knowledge Base</div>
        </div>
        <div style={{ padding: "8px 6px 4px" }}>
          {NAV.map(v => (
            <button key={v.id} onClick={() => setView(v.id)} style={{ display: "flex", alignItems: "center", gap: 8, width: "100%", padding: "7px 10px", border: "none", borderRadius: "var(--border-radius-md)", background: view === v.id ? "var(--color-background-primary)" : "transparent", color: view === v.id ? "var(--color-text-primary)" : "var(--color-text-secondary)", fontSize: 12, cursor: "pointer", textAlign: "left", fontFamily: "var(--font-sans)", marginBottom: 2, fontWeight: view === v.id ? 500 : 400 }}>
              <span style={{ fontSize: 13 }}>{v.icon}</span>{v.label}
            </button>
          ))}
        </div>
        <div style={{ padding: "10px 12px 10px", borderTop: "0.5px solid var(--color-border-tertiary)", marginTop: "auto" }}>
          <div style={{ fontSize: 11, color: "var(--color-text-tertiary)", marginBottom: 3 }}>KNOWLEDGE BASE</div>
          <div style={{ fontSize: 12, color: "var(--color-text-secondary)" }}>✓ {DOCS.length} procedures loaded</div>
          <div style={{ fontSize: 11, color: "var(--color-text-tertiary)", marginTop: 2 }}>✓ {SCRIPTS.length} verbatim scripts</div>
        </div>
      </div>

      {/* Main */}
      <div style={{ flex: 1, display: "flex", flexDirection: "column", overflow: "hidden", minWidth: 0 }}>

        {/* ── CHAT ── */}
        {view === "chat" && <>
          <div style={{ padding: "9px 14px", borderBottom: "0.5px solid var(--color-border-tertiary)", display: "flex", alignItems: "center", justifyContent: "space-between", flexShrink: 0 }}>
            <div>
              <div style={{ fontSize: 13, fontWeight: 500 }}>Chat Assistant</div>
              <div style={{ fontSize: 11, color: "var(--color-text-secondary)" }}>Answering from {DOCS.length} IBCC procedure documents</div>
            </div>
            {messages.length > 0 && <button onClick={() => setMessages([])} style={{ fontSize: 11, color: "var(--color-text-secondary)", background: "none", border: "0.5px solid var(--color-border-tertiary)", borderRadius: "var(--border-radius-md)", padding: "3px 10px", cursor: "pointer", fontFamily: "var(--font-sans)" }}>Clear</button>}
          </div>
          <div style={{ flex: 1, overflowY: "auto", padding: 14 }}>
            {messages.length === 0 && (
              <div>
                <div style={{ fontSize: 12, color: "var(--color-text-secondary)", marginBottom: 8 }}>Quick starts:</div>
                {["What are the exact validation requirements for an inbound account owner?","A customer says their card was stolen — walk me through the steps.","Customer wants to close their account. What's the full procedure?","How do I handle a caller I cannot validate?","A customer reports an Account Takeover — what do I do?","What are the dispute intake steps?"].map((p, i) => (
                  <button key={i} onClick={() => sendMessage(p)} style={{ display: "block", width: "100%", textAlign: "left", background: "var(--color-background-secondary)", border: "0.5px solid var(--color-border-tertiary)", borderRadius: "var(--border-radius-md)", padding: "8px 12px", fontSize: 12, color: "var(--color-text-primary)", cursor: "pointer", fontFamily: "var(--font-sans)", lineHeight: 1.4, marginBottom: 5 }}>{p}</button>
                ))}
              </div>
            )}
            {messages.map((m, i) => (
              <div key={i} style={{ display: "flex", justifyContent: m.role === "user" ? "flex-end" : "flex-start", marginBottom: 12 }}>
                {m.role === "assistant" && <div style={{ width: 24, height: 24, borderRadius: "50%", background: "#4F46E5", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 9, color: "white", fontWeight: 500, marginRight: 8, flexShrink: 0, alignSelf: "flex-start", marginTop: 1 }}>AI</div>}
                <div style={{ maxWidth: "80%", padding: "9px 13px", borderRadius: m.role === "user" ? "13px 13px 3px 13px" : "3px 13px 13px 13px", background: m.role === "user" ? "#4F46E5" : "var(--color-background-secondary)", color: m.role === "user" ? "white" : "var(--color-text-primary)", border: m.role === "user" ? "none" : "0.5px solid var(--color-border-tertiary)" }}>
                  {m.role === "user" ? <p style={{ fontSize: 13, margin: 0, lineHeight: 1.5 }}>{m.text}</p> : <div>{formatMsg(m.text)}</div>}
                </div>
              </div>
            ))}
            {loading && <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 12 }}>
              <div style={{ width: 24, height: 24, borderRadius: "50%", background: "#4F46E5", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 9, color: "white", fontWeight: 500 }}>AI</div>
              <div style={{ padding: "9px 13px", background: "var(--color-background-secondary)", border: "0.5px solid var(--color-border-tertiary)", borderRadius: "3px 13px 13px 13px", fontSize: 12, color: "var(--color-text-secondary)" }}>Searching procedures...</div>
            </div>}
            <div ref={chatEndRef} />
          </div>
          <div style={{ padding: "10px 14px", borderTop: "0.5px solid var(--color-border-tertiary)", flexShrink: 0 }}>
            <div style={{ display: "flex", gap: 8 }}>
              <textarea ref={inputRef} value={input} onChange={e => setInput(e.target.value)} onKeyDown={handleKey} placeholder="Ask about any IBCC procedure or policy..." rows={2} style={{ flex: 1, resize: "none", border: "0.5px solid var(--color-border-secondary)", borderRadius: "var(--border-radius-md)", padding: "7px 11px", fontSize: 13, fontFamily: "var(--font-sans)", lineHeight: 1.5, background: "var(--color-background-primary)", color: "var(--color-text-primary)", outline: "none" }} />
              <button onClick={() => sendMessage()} disabled={loading || !input.trim()} style={{ padding: "0 16px", background: "#4F46E5", border: "none", borderRadius: "var(--border-radius-md)", color: "white", fontSize: 13, fontWeight: 500, cursor: loading || !input.trim() ? "not-allowed" : "pointer", opacity: loading || !input.trim() ? 0.5 : 1, fontFamily: "var(--font-sans)", flexShrink: 0 }}>Send</button>
            </div>
            <div style={{ fontSize: 10, color: "var(--color-text-tertiary)", marginTop: 4 }}>Enter to send · Shift+Enter for new line</div>
          </div>
        </>}

        {/* ── SEARCH ── */}
        {view === "search" && <>
          <div style={{ padding: "10px 14px 10px", borderBottom: "0.5px solid var(--color-border-tertiary)", flexShrink: 0 }}>
            <div style={{ fontSize: 13, fontWeight: 500, marginBottom: 8 }}>Search procedures</div>
            <input ref={searchRef} value={searchQuery} onChange={e => doSearch(e.target.value)} placeholder="Search keywords, topics, or procedures... (e.g. 'lost card', 'validation', 'autopay')" style={{ width: "100%", border: "0.5px solid var(--color-border-secondary)", borderRadius: "var(--border-radius-md)", padding: "8px 12px", fontSize: 13, fontFamily: "var(--font-sans)", background: "var(--color-background-primary)", color: "var(--color-text-primary)", outline: "none", boxSizing: "border-box" }} />
            {searchQuery && <div style={{ fontSize: 11, color: "var(--color-text-tertiary)", marginTop: 5 }}>{searchResults.length} result{searchResults.length !== 1 ? "s" : ""} found</div>}
          </div>
          <div style={{ flex: 1, overflowY: "auto", padding: 14 }}>
            {!searchQuery && (
              <div>
                <div style={{ fontSize: 12, color: "var(--color-text-secondary)", marginBottom: 10 }}>Try searching for:</div>
                {["lost card","autopay","ATO","dispute","validation","closure","STIP","suspended","rewards","name change","translator"].map((t, i) => (
                  <button key={i} onClick={() => doSearch(t)} style={{ display: "inline-block", margin: "0 6px 6px 0", padding: "4px 12px", background: "var(--color-background-secondary)", border: "0.5px solid var(--color-border-tertiary)", borderRadius: 20, fontSize: 12, color: "var(--color-text-secondary)", cursor: "pointer", fontFamily: "var(--font-sans)" }}>{t}</button>
                ))}
              </div>
            )}
            {searchResults.map((r, i) => (
              <div key={i} style={{ background: "var(--color-background-secondary)", border: "0.5px solid var(--color-border-tertiary)", borderRadius: "var(--border-radius-lg)", padding: "12px 14px", marginBottom: 8 }}>
                <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 6 }}>
                  <div style={{ fontSize: 13, fontWeight: 500, color: "var(--color-text-primary)" }}>📄 {r.doc.name}</div>
                  <button onClick={() => sendMessage(`Tell me about: ${r.doc.name}`)} style={{ fontSize: 11, background: "#4F46E5", color: "white", border: "none", borderRadius: "var(--border-radius-md)", padding: "3px 10px", cursor: "pointer", fontFamily: "var(--font-sans)", flexShrink: 0, marginLeft: 8 }}>Ask AI ↗</button>
                </div>
                {r.snippets.length > 0 && r.snippets.map((s, j) => (
                  <div key={j} style={{ fontSize: 11, color: "var(--color-text-secondary)", lineHeight: 1.5, padding: "2px 0", borderLeft: "2px solid var(--color-border-secondary)", paddingLeft: 8, marginBottom: 3 }}>
                    {highlight(s, searchQuery)}
                  </div>
                ))}
                <div style={{ display: "flex", gap: 4, flexWrap: "wrap", marginTop: 6 }}>
                  {r.doc.tags.filter(t => t.toLowerCase().includes(searchQuery.toLowerCase())).slice(0, 4).map((t, j) => (
                    <span key={j} style={{ fontSize: 10, padding: "2px 7px", background: "var(--color-background-primary)", border: "0.5px solid var(--color-border-tertiary)", borderRadius: 20, color: "var(--color-text-tertiary)" }}>{t}</span>
                  ))}
                </div>
              </div>
            ))}
          </div>
        </>}

        {/* ── BROWSE ── */}
        {view === "browse" && <>
          <div style={{ padding: "10px 14px", borderBottom: "0.5px solid var(--color-border-tertiary)", flexShrink: 0 }}>
            <div style={{ fontSize: 13, fontWeight: 500, marginBottom: 8 }}>Browse by topic</div>
            <input value={browseSearch} onChange={e => setBrowseSearch(e.target.value)} placeholder="Filter topics..." style={{ width: "100%", border: "0.5px solid var(--color-border-secondary)", borderRadius: "var(--border-radius-md)", padding: "6px 11px", fontSize: 12, fontFamily: "var(--font-sans)", background: "var(--color-background-primary)", color: "var(--color-text-primary)", outline: "none", boxSizing: "border-box" }} />
          </div>
          <div style={{ flex: 1, overflowY: "auto", padding: 14 }}>
            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 8 }}>
              {CATEGORIES.filter(c => !browseSearch || c.label.toLowerCase().includes(browseSearch.toLowerCase())).map((cat, i) => (
                <button key={i} onClick={() => sendMessage(cat.q)} style={{ display: "flex", alignItems: "center", gap: 10, padding: "12px 13px", background: "var(--color-background-secondary)", border: "0.5px solid var(--color-border-tertiary)", borderRadius: "var(--border-radius-lg)", cursor: "pointer", textAlign: "left", fontFamily: "var(--font-sans)" }}>
                  <span style={{ fontSize: 18, flexShrink: 0 }}>{cat.icon}</span>
                  <span style={{ fontSize: 12, fontWeight: 500, color: "var(--color-text-primary)", lineHeight: 1.3 }}>{cat.label}</span>
                </button>
              ))}
            </div>
          </div>
        </>}

        {/* ── SCRIPTS (Quick Reference Card) ── */}
        {view === "scripts" && <>
          <div style={{ padding: "10px 14px", borderBottom: "0.5px solid var(--color-border-tertiary)", flexShrink: 0 }}>
            <div style={{ fontSize: 13, fontWeight: 500, marginBottom: 2 }}>Quick Reference Scripts</div>
            <div style={{ fontSize: 11, color: "var(--color-text-secondary)", marginBottom: 8 }}>Verbatim scripts and key language for common situations</div>
            <input value={scriptFilter} onChange={e => setScriptFilter(e.target.value)} placeholder="Filter scripts... (e.g. payment, closure, ATO)" style={{ width: "100%", border: "0.5px solid var(--color-border-secondary)", borderRadius: "var(--border-radius-md)", padding: "6px 11px", fontSize: 12, fontFamily: "var(--font-sans)", background: "var(--color-background-primary)", color: "var(--color-text-primary)", outline: "none", boxSizing: "border-box" }} />
          </div>
          <div style={{ flex: 1, overflowY: "auto", padding: 14 }}>
            {filteredScripts.map((s, i) => (
              <div key={i} style={{ background: "var(--color-background-secondary)", border: "0.5px solid var(--color-border-tertiary)", borderRadius: "var(--border-radius-lg)", padding: "12px 14px", marginBottom: 8 }}>
                <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 7 }}>
                  <div style={{ display: "flex", alignItems: "center", gap: 7 }}>
                    <div style={{ fontSize: 12, fontWeight: 500, color: "var(--color-text-primary)" }}>{s.label}</div>
                    <span style={{ fontSize: 10, padding: "1px 7px", background: "var(--color-background-primary)", border: "0.5px solid var(--color-border-tertiary)", borderRadius: 20, color: "var(--color-text-tertiary)" }}>{s.tag}</span>
                  </div>
                  <button onClick={() => copyScript(s.text, i)} style={{ fontSize: 11, color: copiedIdx === i ? "#16a34a" : "var(--color-text-secondary)", background: "var(--color-background-primary)", border: "0.5px solid var(--color-border-tertiary)", borderRadius: "var(--border-radius-md)", padding: "3px 10px", cursor: "pointer", fontFamily: "var(--font-sans)", flexShrink: 0 }}>
                    {copiedIdx === i ? "✓ Copied" : "Copy"}
                  </button>
                </div>
                <div style={{ fontSize: 12, color: "var(--color-text-primary)", lineHeight: 1.6, background: "var(--color-background-primary)", border: "0.5px solid var(--color-border-tertiary)", borderRadius: "var(--border-radius-md)", padding: "9px 12px", fontStyle: s.text.startsWith('"') ? "italic" : "normal" }}>
                  {s.text}
                </div>
              </div>
            ))}
          </div>
        </>}

        {/* ── DOCS ── */}
        {view === "docs" && <>
          <div style={{ padding: "10px 14px", borderBottom: "0.5px solid var(--color-border-tertiary)", flexShrink: 0 }}>
            <div style={{ fontSize: 13, fontWeight: 500 }}>Loaded procedure documents</div>
            <div style={{ fontSize: 11, color: "var(--color-text-secondary)", marginTop: 2 }}>{DOCS.length} documents active in knowledge base</div>
          </div>
          <div style={{ flex: 1, overflowY: "auto", padding: 14 }}>
            {DOCS.map((d, i) => (
              <div key={i} style={{ display: "flex", alignItems: "center", justifyContent: "space-between", padding: "9px 12px", background: "var(--color-background-secondary)", border: "0.5px solid var(--color-border-tertiary)", borderRadius: "var(--border-radius-md)", marginBottom: 6 }}>
                <div style={{ fontSize: 12, fontWeight: 500, color: "var(--color-text-primary)", overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap", flex: 1 }}>📄 {d.name}</div>
                <button onClick={() => sendMessage(`Walk me through the ${d.name} procedure`)} style={{ fontSize: 11, color: "var(--color-text-secondary)", background: "none", border: "0.5px solid var(--color-border-tertiary)", borderRadius: "var(--border-radius-md)", padding: "2px 8px", cursor: "pointer", fontFamily: "var(--font-sans)", flexShrink: 0, marginLeft: 8 }}>Ask ↗</button>
              </div>
            ))}
          </div>
        </>}
      </div>
    </div>
  );
}
